    private final Map<Opdracht, LocalDate> opdrachtToEindDatum = new HashMap<>();

    private final Map<LocalDate, Persoon> datumToPersoonMap = new HashMap<>();

    private final ListMultimap<LocalDate, PersoonsInhouding> datumToPersoonsInhoudingenMap = ArrayListMultimap.create();
    private final Map<LocalDate, PersoonsFiscaliteit> datumToPersoonsFiscaliteitMap = new HashMap<>();

    private final ListMultimap<IdDatumKey, NlpPrestatie> opperToPrestatiesMap = ArrayListMultimap.create();
