    private final MoneyMap<Integer> opdrachtToOnthaalOudersPatronaleVermindering = new HashMoneyMap<>();
    private final MoneyMap<WerkbonusLuikOpdrachtNrKey> opdrachtToWerkbonusOverdracht = new HashMoneyMap<>();

