    private Money belastbaarOtherVrijwilligeBrandweer = Money.ZERO;
    private Money ruwBelastbaarOtherVrijwilligeBrandweer = Money.ZERO;
    private Money vrijstellingBelastbaarOtherVrijwilligeBrandweer = Money.ZERO;
    private Money verminderingBvWerkbonusFiscaalJaarOtherMonthsLuikA = Money.ZERO;
    private Money werkbonusFiscaalJaarOtherMonthsLuikA = Money.ZERO;

