    public void addOpperToPersoonsData(Opper opper) {
        opdrachtToOppers.put(opper.getOpdracht(), opper);
    }

    public void addOpdrachtEindDatum(Opdracht opdracht, LocalDate eindDatum) {
        opdrachtToEindDatum.put(opdracht, eindDatum);
    }

    @Override
    public Opper getOpperOpDatum(Opdracht opdracht, LocalDate selectieDatum) {
        LocalDate opdrachtEindDatum = opdrachtToEindDatum.get(opdracht);
        LocalDate zoekDatum;
        if (opdrachtEindDatum.isBefore(selectieDatum)) {
            zoekDatum = opdrachtEindDatum;
        } else {
            zoekDatum = selectieDatum;
        }

        Opper gezocht = null;
        Set<Opper> oppers = opdrachtToOppers.get(opdracht);
        for (Opper opper : oppers) {
            if (opper.getActualInterval().contains(zoekDatum)) {
                gezocht = opper;
                break;
            }
        }
        if (gezocht == null) {
            throw new MessageException("Geen opper in de PersoonsDataManager op datum " + zoekDatum);
        }
        return gezocht;
    }

    @Override
    public Persoon getPersoonOpDatum(LocalDate datum) {
        return getPersoonOpDatum(datum, false);
    }

    @Override
    public Persoon getPersoonOpDatum(LocalDate datum, boolean theoretisch) {
        LocalDate eindeMaand = datum.dayOfMonth().withMaximumValue();
        Persoon persoon = datumToPersoonMap.get(eindeMaand);
        if (persoon != null) {
            //Dit is nodig omdat anders deze opdrachten set ook zou worden toegepast op een eerder ophaling van deze persoon.
            persoon = copyPersoon(persoon);
            Set<Opdracht> opdrachten = getOpdrachtenOpDatum(eindeMaand, theoretisch);
            persoon.setOpdrachten(opdrachten);
        }
        return persoon;
    }

    private Persoon copyPersoon(Persoon persoon) {
        Persoon copy = new PersoonPO(persoon.getId());
        copy.setPersoonSlices(persoon.getPersoonSlices());
        copy.setPersoon2Slices(persoon.getPersoon2Slices());
        copy.setPersoonsFiscaliteitSlices(persoon.getPersoonsFiscaliteitSlices());
        copy.setGezinsToestandSlices(persoon.getGezinsToestandSlices());
        return copy;
    }

    public void addPersoonOpDatum(Persoon persoon, LocalDate datum) {
        LocalDate eindeMaand = datum.dayOfMonth().withMaximumValue();
        datumToPersoonMap.put(eindeMaand, persoon);
        datumToOpdrachtenMap.putAll(eindeMaand, persoon.getOpdrachten());
    }

    @Override
    public Set<Opdracht> getOpdrachtenOpDatum(LocalDate eindeMaand, boolean theoretisch) {
        Set<Opdracht> teRekenen = new HashSet<>();
        Set<Opdracht> opdrachten = datumToOpdrachtenMap.get(eindeMaand);
        if (theoretisch) {
            teRekenen.addAll(opdrachten);
        } else {
            for (Opdracht opdracht : opdrachten) {
                if (teRekenenOpdrachtIds.contains(opdracht.getId())) {
                    teRekenen.add(opdracht);
                }
            }
        }
        return teRekenen;
    }

    @Override
    public List<NlpPrestatie> findPrestaties(Opper opper, LocalDate eindeMaand) {
        return opperToPrestatiesMap.get(new IdDatumKey(opper.getId(), eindeMaand));
    }

    public void addPrestaties(Opper opper, LocalDate datum, List<NlpPrestatie> prestaties) {
        LocalDate eindeMaand = datum.dayOfMonth().withMaximumValue();
        opperToPrestatiesMap.putAll(new IdDatumKey(opper.getId(), eindeMaand), prestaties);
        opdrachtIdToPrestatiesMap.putAll(new IdDatumKey(opper.getOpdracht().getId(), eindeMaand), prestaties);
    }

    @Override
    public List<NlpPrestatie> findPrestaties(Opdracht opdracht, LocalDate eindeMaand) {
        return opdrachtIdToPrestatiesMap.get(new IdDatumKey(opdracht.getId(), eindeMaand));
    }

    public void setOpdrachtInOpzegOpEerstDagKwartaal(Opdracht opdracht) {
        opdrachtIdsInOpzegOpEerstDagKwartaal.add(opdracht.getId());
    }

