        beslagDatum = beslagDatum.dayOfMonth().withMaximumValue();
        datumToPersoonsInhoudingenMap.putAll(beslagDatum, persoonsInhoudingen);
    }

    @Override
    public List<PersoonsInhouding> findPersoonsInhoudingenOpBeslagDatum(LocalDate beslagDatum) {
        beslagDatum = beslagDatum.dayOfMonth().withMaximumValue();
