    }

    @Override
    public PersoonsFiscaliteit getPersoonsFiscaliteitOpBeslagDatum(LocalDate beslagDatum) {
        beslagDatum = beslagDatum.dayOfMonth().withMaximumValue();
        return datumToPersoonsFiscaliteitMap.get(beslagDatum);
    }

