    @Override
    public Money getVerminderingBvWerkbonusFiscaalJaarOtherMonths(WerkbonusLuik luik) {
        if (luik == WerkbonusLuik.LUIK_A) {
            return verminderingBvWerkbonusFiscaalJaarOtherMonthsLuikA;
        } else {
            return verminderingBvWerkbonusFiscaalJaarOtherMonthsLuikB;
        }
    }

    @Override
    public Money getWerkbonusFiscaalJaarOtherMonths(WerkbonusLuik luik) {
        if (luik == WerkbonusLuik.LUIK_A) {
            return werkbonusFiscaalJaarOtherMonthsLuikA;
        } else {
            return werkbonusFiscaalJaarOtherMonthsLuikB;
        }
